// Map city name → airport code for quick lookup
export const CITY_TO_AIRPORT: Record<string, string> = {};
CITIES.forEach(c => { CITY_TO_AIRPORT[c.city.toLowerCase()] = c.airport; });

// Merge cities into ALL_LOCATIONS format for AutocompleteInput
export const ALL_LOCATIONS = CITIES.map(c => ({
  type: 'city' as const,
  city: c.city,
  code: c.airport,
  name: c.type,
  state: `${c.state} • ${c.country}`,
}));
